  1	import * as React from 'react';
  2	import { useRawCapacity, useSafeK8sWatchResource } from '@odf/core/hooks';
  3	import { useODFNamespaceSelector } from '@odf/core/redux/selectors';
  4	import {
  5	  odfSubscriptionResource,
  6	  storageClusterResource,
  7	} from '@odf/core/resources';
  8	import { getStorageClusterInNs } from '@odf/core/utils';
  9	import { DANGER_THRESHOLD, WARNING_THRESHOLD } from '@odf/ocs/constants/charts';
 10	import { resiliencyProgressQuery } from '@odf/ocs/queries';
 11	import { getDataResiliencyState } from '@odf/ocs/utils';
 12	import {
 13	  DASH,
 14	  getName,
 15	  healthStateMapping,
 16	  healthStateMessage,
 17	  ODF_OPERATOR,
 18	  resourceStatus,
 19	  Status,
 20	  StorageClusterKind,
 21	  SubscriptionKind,
 22	  useFetchCsv,
 23	} from '@odf/shared';
 24	import { ErrorCardBody } from '@odf/shared/generic/ErrorCardBody';
 25	import {
 26	  useCustomPrometheusPoll,
 27	  usePrometheusBasePath,
 28	} from '@odf/shared/hooks/custom-prometheus-poll';
 29	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 30	import {
 31	  getOprChannelFromSub,
 32	  getOprVersionFromCSV,
 33	  getStorageClusterMetric,
 34	  humanizeBinaryBytes,
 35	} from '@odf/shared/utils';
 36	import {
 37	  HealthState,
 38	  useK8sWatchResource,
 39	} from '@openshift-console/dynamic-plugin-sdk';
 40	import { chart_color_blue_100 as general2 } from '@patternfly/react-tokens/dist/js/chart_color_blue_100';
 41	import { chart_color_blue_300 as general1 } from '@patternfly/react-tokens/dist/js/chart_color_blue_300';
 42	import { t_global_color_status_danger_default as danger1 } from '@patternfly/react-tokens/dist/js/t_global_color_status_danger_default';
 43	import { t_global_color_status_warning_default as warning1 } from '@patternfly/react-tokens/dist/js/t_global_color_status_warning_default';
 44	import classNames from 'classnames';
 45	import * as _ from 'lodash-es';
 46	import { useNavigate } from 'react-router-dom-v5-compat';
 47	import { ChartDonut, ChartLabel, ChartLegend } from '@patternfly/react-charts';
 48	import {
 49	  DescriptionList,
 50	  DescriptionListTerm,
 51	  DescriptionListGroup,
 52	  DescriptionListDescription,
 53	  Button,
 54	  ButtonVariant,
 55	  Skeleton,
 56	} from '@patternfly/react-core';
 57	import {
 58	  Card,
 59	  CardBody,
 60	  CardHeader,
 61	  CardProps,
 62	  CardTitle,
 63	  Grid,
 64	  GridItem,
 65	} from '@patternfly/react-core';
 66	import { ArrowRightIcon } from '@patternfly/react-icons';
 67	import './StorageClusterCard.scss';
 68	
 69	const generalColorScale = [general1.value, general2.value];
 70	const warningColorScale = [warning1.value, general2.value];
 71	const dangerColorScale = [danger1.value, general2.value];
 72	
 73	export const StorageClusterCard: React.FC<CardProps> = ({ className }) => {
 74	  const { t } = useCustomTranslation();
 75	  const navigate = useNavigate();
 76	  const [storageClusters, storageClustersLoaded, storageClustersError] =
 77	    useK8sWatchResource<StorageClusterKind[]>(storageClusterResource);
 78	  const { odfNamespace, isNsSafe } = useODFNamespaceSelector();
 79	  const [csv, csvLoaded, csvError] = useFetchCsv({
 80	    specName: ODF_OPERATOR,
 81	    namespace: odfNamespace,
 82	    startPollingInstantly: isNsSafe,
 83	  });
 84	  const [subscription, subscriptionLoaded, subscriptionError] =
 85	    useSafeK8sWatchResource<SubscriptionKind>(odfSubscriptionResource);
 86	
 87	  const storageCluster = getStorageClusterInNs(storageClusters, odfNamespace);
 88	  const clusterName = getName(storageCluster);
 89	  const [totalCapacity, usedCapacity, capacityLoading, capacityLoadError] =
 90	    useRawCapacity(clusterName);
 91	  const [resiliencyProgress, resiliencyProgressError] = useCustomPrometheusPoll(
 92	    {
 93	      query: resiliencyProgressQuery(clusterName),
 94	      endpoint: 'api/v1/query' as any,
 95	      basePath: usePrometheusBasePath(),
 96	    }
 97	  );
 98	  const dataResiliencyState = getDataResiliencyState(
 99	    [{ response: resiliencyProgress, error: resiliencyProgressError }],
100	    t
101	  );
102	  const resiliencyMessage =
103	    dataResiliencyState.state === HealthState.OK
104	      ? t('Healthy')
105	      : healthStateMessage(dataResiliencyState.state, t);
106	  const resiliencyIcon = healthStateMapping?.[dataResiliencyState.state]?.icon;
107	
108	  const odfVersion =
109	    csvLoaded && _.isEmpty(csvError) ? getOprVersionFromCSV(csv) : DASH;
110	
111	  const clusterVersionChannel =
112	    subscriptionLoaded && !subscriptionError
113	      ? getOprChannelFromSub(subscription)
114	      : DASH;
115	
116	  const usedCapacityData = getStorageClusterMetric(
117	    usedCapacity,
118	    clusterName,
119	    odfNamespace
120	  );
121	  const totalCapacityData = getStorageClusterMetric(
122	    totalCapacity,
123	    clusterName,
124	    odfNamespace
125	  );
126	  const totalCapacityValue = humanizeBinaryBytes(totalCapacityData?.value?.[1]);
127	  const showCapacityChart =
128	    !capacityLoading && !capacityLoadError && totalCapacityValue.value > 0;
129	  const usedCapacityValue = humanizeBinaryBytes(
130	    usedCapacityData?.value?.[1],
131	    null,
132	    totalCapacityValue?.unit
133	  );
134	  const usedCapacityNotRelativeToTotal = humanizeBinaryBytes(
135	    usedCapacityData?.value?.[1]
136	  );
137	  const availableCapacityValue = humanizeBinaryBytes(
138	    !!usedCapacityData?.value?.[1] && !!totalCapacityData?.value?.[1]
139	      ? Number(totalCapacityData.value?.[1]) -
140	          Number(usedCapacityData.value?.[1])
141	      : 0,
142	    null,
143	    totalCapacityValue?.unit
144	  );
145	  const donutData = [
146	    { x: 'Used', y: usedCapacityValue.value, string: usedCapacityValue.string },
147	    {
148	      x: 'Available',
149	      y: availableCapacityValue.value,
150	      string: availableCapacityValue.string,
151	    },
152	  ];
153	
154	  const capacityRatio = parseFloat(
155	    (usedCapacityValue.value / totalCapacityValue.value).toFixed(2)
156	  );
157	
158	  const colorScale = React.useMemo(() => {
159	    if (capacityRatio > DANGER_THRESHOLD) return dangerColorScale;
160	    if (capacityRatio > WARNING_THRESHOLD && capacityRatio <= DANGER_THRESHOLD)
161	      return warningColorScale;
162	    return generalColorScale;
163	  }, [capacityRatio]);
164	
165	  return (
166	    <Card className={classNames(className)} isFlat={true}>
167	      <CardHeader>
168	        <CardTitle>{t('Storage cluster')}</CardTitle>
169	      </CardHeader>
170	      <CardBody>
171	        {storageClustersLoaded && !storageClustersError && !!storageCluster && (
172	          <Grid hasGutter>
173	            <GridItem md={4} sm={12}>
174	              <DescriptionList>
175	                <DescriptionListGroup>
176	                  <DescriptionListTerm>
177	                    {t('Cluster Status')}
178	                  </DescriptionListTerm>
179	                  <DescriptionListDescription>
180	                    <Status status={resourceStatus(storageCluster)} />
181	                  </DescriptionListDescription>
182	                </DescriptionListGroup>
183	                <DescriptionListGroup>
184	                  <DescriptionListTerm>{t('Resiliency')}</DescriptionListTerm>
185	                  <DescriptionListDescription>
186	                    {resiliencyIcon}
187	                    <span className="pf-v6-u-ml-xs">{resiliencyMessage}</span>
188	                  </DescriptionListDescription>
189	                </DescriptionListGroup>
190	                <DescriptionListGroup>
191	                  <DescriptionListTerm>
192	                    {t('Data Foundation version')}
193	                  </DescriptionListTerm>
194	                  <DescriptionListDescription>
195	                    {odfVersion}
196	                  </DescriptionListDescription>
197	                </DescriptionListGroup>
198	                <DescriptionListGroup>
199	                  <DescriptionListTerm>
200	                    {t('Update channel')}
201	                  </DescriptionListTerm>
202	                  <DescriptionListDescription>
203	                    {clusterVersionChannel}
204	                  </DescriptionListDescription>
205	                </DescriptionListGroup>
206	              </DescriptionList>
207	            </GridItem>
208	            <GridItem
209	              md={8}
210	              rowSpan={2}
211	              sm={12}
212	              className="odf-cluster-card__chart-container"
213	            >
214	              {showCapacityChart ? (
215	                <ChartDonut
216	                  ariaDesc={t('Available versus Used Capacity')}
217	                  ariaTitle={t('Available versus Used Capacity')}
218	                  height={150}
219	                  width={300}
220	                  data={donutData}
221	                  labels={({ datum }) => `${datum.string}`}
222	                  title={usedCapacityNotRelativeToTotal.value}
223	                  subTitle={usedCapacityNotRelativeToTotal.unit}
224	                  colorScale={colorScale}
225	                  padding={{ top: 0, bottom: 0, left: 0, right: 140 }}
226	                  constrainToVisibleArea
227	                  titleComponent={
228	                    <ChartLabel
229	                      className="odf-cluster-card__chart-title"
230	                      style={{
231	                        fill: 'var(--pf-t--global--text--color--regular)',
232	                        fontSize: 20,
233	                      }}
234	                    />
235	                  }
236	                  subTitleComponent={
237	                    <ChartLabel
238	                      className="odf-cluster-card__chart-subtitle"
239	                      style={{ fill: 'var(--pf-t--global--text--color--subtle)' }}
240	                      dy={5}
241	                    />
242	                  }
243	                  legendComponent={
244	                    <ChartLegend
245	                      orientation="vertical"
246	                      gutter={20}
247	                      style={{
248	                        labels: { fill: 'var(--pf-t--global--text--color--subtle)' },
249	                      }}
250	                    />
251	                  }
252	                  legendData={[
253	                    {
254	                      name: `${t('Used')}: ${usedCapacityNotRelativeToTotal.string}`,
255	                    },
256	                    {
257	                      name: `${t('Available')}: ${availableCapacityValue.string}`,
258	                    },
259	                  ]}
260	                  legendOrientation="vertical"
261	                  legendPosition="right"
262	                />
263	              ) : (
264	                <>{t('No capacity data available.')}</>
265	              )}
266	            </GridItem>
267	            <GridItem md={4} sm={12}>
268	              <Button
269	                variant={ButtonVariant.link}
270	                icon={<ArrowRightIcon />}
271	                iconPosition="end"
272	                className="pf-v6-u-font-size-lg odf-cluster-card__storage-link"
273	                component="a"
274	                onClick={() => navigate('/odf/storage-cluster')}
275	              >
276	                {t('View storage')}
277	              </Button>
278	            </GridItem>
279	          </Grid>
280	        )}
281	        {storageClustersLoaded && !storageClustersError && !storageCluster && (
282	          <ErrorCardBody title={t('No storage cluster configured.')} />
283	        )}
284	        {!storageClustersLoaded && !storageClustersError && (
285	          <Skeleton
286	            height="100%"
287	            screenreaderText={t('Loading storage cluster data')}
288	          />
289	        )}
290	        {storageClustersError && (
291	          <ErrorCardBody title={t('Storage cluster data not available.')} />
292	        )}
293	      </CardBody>
294	    </Card>
295	  );
296	};

